+const STATEMENT_REUSE_TRACE_CAPACITY: usize = 1_024;
+
+#[derive(Debug, Clone, PartialEq, Eq)]
+struct StatementReuseLaneContext {
+    worker_id: String,
+    node_id: String,
+}
+
+impl StatementReuseLaneContext {
+    fn from_runtime() -> Self {
+        let worker_id = std::env::var("WORKER_ID")
+            .or_else(|_| std::env::var("FSQLITE_WORKER_ID"))
+            .unwrap_or_else(|_| {
+                let thread = std::thread::current();
+                thread
+                    .name()
+                    .map_or_else(|| format!("{:?}", thread.id()), ToOwned::to_owned)
+            });
+        let node_id = std::env::var("NODE_ID")
+            .or_else(|_| std::env::var("FSQLITE_NODE_ID"))
+            .or_else(|_| std::env::var("HOSTNAME"))
+            .unwrap_or_else(|_| "(local)".to_owned());
+        Self { worker_id, node_id }
+    }
+}
