+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+enum StatementReuseLaneLocality {
+    FirstObservation,
+    SameLane,
+    CrossLane,
+    CrossNode,
+}
+
+impl StatementReuseLaneLocality {
+    const fn as_str(self) -> &'static str {
+        match self {
+            Self::FirstObservation => "first_observation",
+            Self::SameLane => "same_lane",
+            Self::CrossLane => "cross_lane",
+            Self::CrossNode => "cross_node",
+        }
+    }
+}
+
+#[derive(Debug, Clone, PartialEq, Eq, Hash)]
+struct StatementReuseTraceKey {
+    cache_kind: &'static str,
+    statement_fingerprint: String,
+}
+
+#[derive(Debug, Clone, PartialEq, Eq)]
+struct StatementReuseLastSeen {
+    cache_sequence: u64,
+    worker_id: String,
+    node_id: String,
+}
+
+#[derive(Debug, Clone, PartialEq, Eq)]
+struct StatementReuseTraceEntry {
+    cache_kind: &'static str,
+    statement_fingerprint: String,
+    cache_sequence: u64,
+    cache_hit: bool,
+    reuse_distance: Option<u64>,
+    lane_locality: StatementReuseLaneLocality,
+    worker_id: String,
+    node_id: String,
+    previous_worker_id: Option<String>,
+    previous_node_id: Option<String>,
+}
+
+#[derive(Debug, Default)]
+struct StatementReuseTraceState {
+    next_sequence_by_cache_kind: HashMap<&'static str, u64>,
+    last_seen: HashMap<StatementReuseTraceKey, StatementReuseLastSeen>,
+    recent: VecDeque<StatementReuseTraceEntry>,
+}
+
+impl StatementReuseTraceState {
+    fn clear(&mut self) {
+        self.next_sequence_by_cache_kind.clear();
+        self.last_seen.clear();
+        self.recent.clear();
+    }
+
+    fn record(
+        &mut self,
+        cache_kind: &'static str,
+        statement_fingerprint: &str,
+        cache_hit: bool,
+        lane: StatementReuseLaneContext,
+    ) -> StatementReuseTraceEntry {
+        let cache_sequence_entry = self.next_sequence_by_cache_kind.entry(cache_kind).or_default();
+        *cache_sequence_entry = (*cache_sequence_entry).saturating_add(1);
+        let cache_sequence = *cache_sequence_entry;
+        let trace_key = StatementReuseTraceKey {
+            cache_kind,
+            statement_fingerprint: statement_fingerprint.to_owned(),
+        };
+        let previous = self.last_seen.insert(
+            trace_key,
+            StatementReuseLastSeen {
+                cache_sequence,
+                worker_id: lane.worker_id.clone(),
+                node_id: lane.node_id.clone(),
+            },
+        );
+
+        let (reuse_distance, lane_locality, previous_worker_id, previous_node_id) =
+            if let Some(previous) = previous {
+                let lane_locality = if previous.node_id != lane.node_id {
+                    StatementReuseLaneLocality::CrossNode
+                } else if previous.worker_id != lane.worker_id {
+                    StatementReuseLaneLocality::CrossLane
+                } else {
+                    StatementReuseLaneLocality::SameLane
+                };
+                (
+                    Some(
+                        cache_sequence
+                            .saturating_sub(previous.cache_sequence)
+                            .saturating_sub(1),
+                    ),
+                    lane_locality,
+                    Some(previous.worker_id),
+                    Some(previous.node_id),
+                )
+            } else {
+                (
+                    None,
+                    StatementReuseLaneLocality::FirstObservation,
+                    None,
+                    None,
+                )
+            };
+
+        let entry = StatementReuseTraceEntry {
+            cache_kind,
+            statement_fingerprint: statement_fingerprint.to_owned(),
+            cache_sequence,
+            cache_hit,
+            reuse_distance,
+            lane_locality,
+            worker_id: lane.worker_id,
+            node_id: lane.node_id,
+            previous_worker_id,
+            previous_node_id,
+        };
+
+        if self.recent.len() == STATEMENT_REUSE_TRACE_CAPACITY {
+            self.recent.pop_front();
+        }
+        self.recent.push_back(entry.clone());
+        entry
+    }
+}
